function throttleWithJitter(fn, waitMs, jitterMs = 0) {
  let lastRunAt = 0;
  let timer = null;
  let queuedArgs = null;
  return function throttled(...args) {
    const now = Date.now();
    const jitter = jitterMs > 0 ? Math.floor(Math.random() * (jitterMs + 1)) : 0;
    const elapsed = now - lastRunAt;
    const remaining = waitMs + jitter - elapsed;
    queuedArgs = args;
    if (remaining <= 0) {
      lastRunAt = now;
      fn.apply(this, queuedArgs);
      queuedArgs = null;
      return;
    }
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => {
      lastRunAt = Date.now();
      timer = null;
      fn.apply(this, queuedArgs ?? []);
      queuedArgs = null;
    }, remaining);
  };
}
